 1	import type { FC } from 'react';
 2	import { Link } from 'react-router-dom-v5-compat';
 3	import TabTitle from 'src/overview/components/TabTitle';
 4	import { useForkliftTranslation } from 'src/utils/i18n';
 5	
 6	import LoadingSuspend from '@components/LoadingSuspend';
 7	import type { IoK8sApiCoreV1Pod, V1beta1ForkliftController } from '@kubev2v/types';
 8	import { useK8sWatchResource } from '@openshift-console/dynamic-plugin-sdk';
 9	import { Card, CardBody, CardHeader, CardTitle } from '@patternfly/react-core';
10	
11	import { PodsTable } from './PodsTable';
12	
13	type ControllerCardProps = {
14	  obj?: V1beta1ForkliftController;
15	  limit?: number;
16	};
17	
18	const ControllerCard: FC<ControllerCardProps> = ({ limit, obj }) => {
19	  const { t } = useForkliftTranslation();
20	
21	  const [pods, loaded, loadError] = useK8sWatchResource<IoK8sApiCoreV1Pod[]>({
22	    isList: true,
23	    kind: 'Pod',
24	    limit,
25	    namespace: obj?.metadata?.namespace,
26	    namespaced: true,
27	    selector: { matchLabels: { app: 'forklift' } },
28	  });
29	
30	  return (
31	    <Card className="pf-m-full-height">
32	      <CardHeader
33	        actions={{
34	          actions: limit ? <Link to={'health'}>View all</Link> : null,
35	        }}
36	      >
37	        <CardTitle className="forklift-title">
38	          <TabTitle
39	            title={t('Health')}
40	            helpContent={t(
41	              'Health indicates the current status of the pods related to the Migration Toolkit for Virtualization, including whether any have failed. For more details, refer to the logs.',
42	            )}
43	          />
44	        </CardTitle>
45	      </CardHeader>
46	      <LoadingSuspend obj={pods} loaded={loaded} loadError={loadError}>
47	        <CardBody>
48	          <div className="forklift-overview__pods-table">
49	            <PodsTable pods={pods} limit={limit} />
50	          </div>
51	        </CardBody>
52	      </LoadingSuspend>
53	    </Card>
54	  );
55	};
56	
57	export default ControllerCard;

